const now = new Date();
const period = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
const timestamp = now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14);
const runToken = Math.random().toString(16).slice(2, 8);
const billingApiBaseUrl = 'https://your-billing-api.example.com';
const billingApiToken = '';
const reportFileTypes = [];
const configFile = '';
const lookerClientId = '';
const lookerClientSecret = '';
const historyWindowDays = 90;
if (!billingApiBaseUrl || billingApiBaseUrl.includes('your-billing-api.example.com')) {
  throw new Error('Set billingApiBaseUrl in the Build Config node before running this cloud workflow.');
}
const requestBody = {
  period,
  runId: `n8n-cloud-${timestamp}-${runToken}-${period.replace('-', '')}`,
  dryRun: false,
  reportTimeout: 600,
  historyWindowDays,
};
if (reportFileTypes.length) {
  requestBody.reportFileTypes = reportFileTypes;
}
if (configFile) {
  requestBody.configFile = configFile;
}
if (lookerClientId) {
  requestBody.lookerClientId = lookerClientId;
}
if (lookerClientSecret) {
  requestBody.lookerClientSecret = lookerClientSecret;
}
return [{
  json: {
    period,
    billingApiBaseUrl: billingApiBaseUrl.replace(/\/$/, ''),
    billingApiToken,
    requestBody,
  }
}];

const reports = Array.isArray($json.reports) ? $json.reports : [];
const errors = reports.filter((report) => report.status === 'error').map((report) => ({
  fileType: report.fileType,
  error: report.error,
}));
const warnings = reports.flatMap((report) => (report.warnings || []).map((warning) => `${report.fileType}: ${warning}`));
return [{
  json: {
    period: $json.period,
    runId: $json.runId,
    savedAt: $json.savedAt || null,
    configuredCount: $json.configuredCount ?? reports.length,
    importedCount: $json.importedCount ?? reports.filter((report) => report.status === 'imported').length,
    errorCount: $json.errorCount ?? errors.length,
    warningCount: $json.warningCount ?? warnings.length,
    hasErrors: $json.hasErrors ?? Boolean(errors.length),
    hasWarnings: $json.hasWarnings ?? Boolean(warnings.length),
    reports: reports.map((report) => ({
      fileType: report.fileType,
      status: report.status,
      changedGroups: report.changeSummary?.totalChangedGroups || 0,
      warnings: report.warnings || [],
    })),
    errors,
    warnings,
    raw: $json,
  }
}];
